const norm = s => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\b(sa|sas|sarl|sasu|eurl|group|groupe|holding|france|se)\b/g, ' ').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
const companies = $input.all().map(it => it.json);
const contacts = $('Airtable : Contacts').all().map(it => it.json);
const compNames = new Set(companies.map(c => norm(c['Company Name'])).filter(Boolean));
let total = 0, avecLien = 0, sansLien = 0, sansEmployeur = 0, c1 = 0, c2 = 0;
const c2set = new Set(); const c2samples = [];
for (const ct of contacts) {
  total++;
  const ent = ct['Entreprise']; const co2 = ct['Companies 2'];
  const hasLink = (Array.isArray(ent) && ent.length) || (Array.isArray(co2) && co2.length);
  if (hasLink) { avecLien++; continue; }
  sansLien++;
  const emp = (ct['Company Name'] || '').toString().trim();
  if (!emp) { sansEmployeur++; continue; }
  if (compNames.has(norm(emp))) { c1++; }
  else { c2++; const k = norm(emp); if (!c2set.has(k)) { c2set.add(k); if (c2samples.length < 25) c2samples.push(emp); } }
}
return [{ json: {
  total_contacts: total,
  avec_lien_societe: avecLien,
  SANS_lien: sansLien,
  '  dont sans employeur (texte vide)': sansEmployeur,
  '  dont C1 (employeur DEJA dans Companies, lien a poser)': c1,
  '  dont C2 (employeur ABSENT, a incuber)': c2,
  C2_employeurs_distincts: c2set.size,
  C2_exemples: c2samples.join(' | ')
} }];
